mlir::OwningOpRef<mlir::ModuleOp> parseModule(mlir::MLIRContext &context,
                                              llvm::StringRef source) {
  return mlir::parseSourceString<mlir::ModuleOp>(source, &context);
}

KernelOp findKernel(mlir::ModuleOp module, llvm::StringRef name) {
  KernelOp kernel;
  module->walk([&](KernelOp candidate) {
    if (candidate.getSymName() == name)
      kernel = candidate;
  });
  return kernel;
}

VariantOp findVariant(KernelOp kernel, llvm::StringRef name) {
  VariantOp variant;
  if (!kernel || kernel.getBody().empty())
    return variant;
  for (mlir::Operation &op : kernel.getBody().front()) {
    auto candidate = llvm::dyn_cast<VariantOp>(op);
    if (candidate && candidate.getSymName() == name)
      variant = candidate;
  }
  return variant;
}

llvm::Expected<tianchenrv::plugin::rvv::RVVSelectedBodyRouteAnalysis>
analyzeRouteInModule(mlir::ModuleOp module, llvm::StringRef kernelName,
                     llvm::StringRef variantName) {
  KernelOp kernel = findKernel(module, kernelName);
  if (!kernel)
    return tianchenrv::plugin::rvv::makeRVVEmitCRouteProviderError(
        llvm::Twine("missing test kernel '") + kernelName + "'");
  VariantOp variant = findVariant(kernel, variantName);
  if (!variant)
    return tianchenrv::plugin::rvv::makeRVVEmitCRouteProviderError(
        llvm::Twine("missing test variant '") + variantName + "'");
  return tianchenrv::plugin::rvv::analyzeRVVSelectedBodyRoute(
      VariantEmitCLowerableRequest(
          variant, kernel, TargetCapabilitySet::buildFromKernel(kernel),
          VariantEmissionRole::DirectVariant));
}

int expectTypedConfigFacts(
    const tianchenrv::plugin::rvv::RVVSelectedBodyRouteAnalysis &analysis,
    llvm::StringRef elementTypeName, std::int64_t sew,
    llvm::StringRef lmul, llvm::StringRef vectorTypeName,
    llvm::StringRef vectorCType, llvm::StringRef setVLIntrinsic,
    llvm::StringRef loadIntrinsic, llvm::StringRef storeIntrinsic,
    llvm::StringRef context) {
  using tianchenrv::plugin::rvv::getRVVSelectedBodyRouteMaterializationFacts;
  const auto &facts = analysis.typedConfigFacts;
  if (int result =
          expect(facts.hasFacts(), llvm::Twine(context) +
                                       " exposes typed config facts"))
    return result;
  if (int result = expect(
          facts.elementTypeName == elementTypeName &&
              facts.elementBitWidth == sew && facts.sew == sew &&
              facts.lmul == lmul && facts.vectorTypeName == vectorTypeName &&
              facts.vectorCType == vectorCType &&
              facts.setVLIntrinsic == setVLIntrinsic &&
              facts.vectorLoadIntrinsic == loadIntrinsic &&
              facts.storeIntrinsic == storeIntrinsic,
          llvm::Twine(context) +
              " derives element type, SEW, LMUL, vector C type, and "
              "intrinsic leaves from realized typed RVV config"))
    return result;

  std::string materializationContext =
      (llvm::Twine(context) + " materialization facts").str();
  llvm::Expected<
      tianchenrv::plugin::rvv::RVVSelectedBodyRouteMaterializationFacts>
      materializationFacts = getRVVSelectedBodyRouteMaterializationFacts(
          analysis, materializationContext);
  if (!materializationFacts)
    return fail(llvm::Twine(context) + " materialization facts: " +
                llvm::toString(materializationFacts.takeError()));
  return expect(materializationFacts->typedConfigFacts.hasFacts() &&
                    materializationFacts->typedConfigFacts.elementTypeName ==
                        elementTypeName &&
                    materializationFacts->typedConfigFacts.vectorCType ==
                        vectorCType &&
                    materializationFacts->typedConfigFacts.setVLIntrinsic ==
                        setVLIntrinsic,
                llvm::Twine(context) +
                    " preserves typed config facts into provider "
                    "materialization facts");
}

bool routeHasTypeMapping(
    const tianchenrv::conversion::emitc::TCRVEmitCLowerableRoute &route,
    llvm::StringRef sourceType, llvm::StringRef cType) {
  for (const tianchenrv::conversion::emitc::TCRVEmitCTypeMapping &mapping :
       route.getTypeMappings())
    if (mapping.sourceType == sourceType && mapping.cType == cType)
      return true;
  return false;
}

bool routeHasHeader(
    const tianchenrv::conversion::emitc::TCRVEmitCLowerableRoute &route,
    llvm::StringRef header) {
  for (const tianchenrv::conversion::emitc::TCRVEmitCHeaderRequirement
           &requirement : route.getHeaders())
    if (requirement.header == header)
      return true;
  return false;
}

bool routeABIMappingsMatchDescription(
    const tianchenrv::conversion::emitc::TCRVEmitCLowerableRoute &route,
    const tianchenrv::plugin::rvv::RVVSelectedBodyEmitCRouteDescription
        &description) {
  if (route.getABIMappings().size() !=
      description.runtimeABIParameters.size())
    return false;
  for (std::size_t index = 0; index < route.getABIMappings().size();
       ++index) {
    const tianchenrv::conversion::emitc::TCRVEmitCABIValueMapping &mapping =
        route.getABIMappings()[index];
    const tianchenrv::support::RuntimeABIParameter &parameter =
        description.runtimeABIParameters[index];
    if (mapping.valueName != parameter.cName ||
        mapping.parameter.cName != parameter.cName ||
        mapping.parameter.cType != parameter.cType ||
        mapping.parameter.role != parameter.role ||
        mapping.parameter.ownership != parameter.ownership)
      return false;
  }
  return true;
}

int expectRouteConsumesTypedConfigFacts(
    const tianchenrv::conversion::emitc::TCRVEmitCLowerableRoute &route,
    llvm::StringRef vectorTypeName, llvm::StringRef vectorCType,
    llvm::StringRef vlCType, llvm::StringRef context);

int expectSegment2RouteConsumesProviderPlan(
    const tianchenrv::conversion::emitc::TCRVEmitCLowerableRoute &route,
    const tianchenrv::plugin::rvv::
        RVVSelectedBodySegment2RouteFamilyProviderPlan &plan,
    const tianchenrv::plugin::rvv::RVVSelectedBodyEmitCRouteDescription
        &description,
    bool computedMask, llvm::StringRef context) {
  if (int result = expect(
          plan.plansSegment2MemoryRoute &&
              plan.emitCRouteID == description.emitCRouteID &&
              plan.providerSupportedMirror ==
                  description.providerSupportedMirror &&
              plan.runtimeABIOrderMirror == description.runtimeABIOrder &&
              (description.segment2MemoryRouteFamilyPlanID.empty() ||
               plan.familyPlanIDMirror ==
                   description.segment2MemoryRouteFamilyPlanID) &&
              plan.routeOperandBindingPlanIDMirror ==
                  description.routeOperandBindingPlanID &&
              plan.routeOperandBindingSummaryMirror ==
                  description.routeOperandBindingSummary,
          llvm::Twine(context) +
              " provider plan mirrors selected-body family, route, ABI, "
              "support, and operand-binding facts"))
    return result;
  if (int result = expect(
          !plan.requiredHeaders.empty() &&
              plan.requiredHeaderDeclarationsMirror ==
                  description.requiredHeaderDeclarations &&
              plan.cTypeMappingSummaryMirror ==
                  description.cTypeMappingSummary,
          llvm::Twine(context) +
              " provider plan carries owner-built header and C type facts"))
    return result;
  if (int result = expect(route.getRouteID() == plan.emitCRouteID,
                          llvm::Twine(context) +
                              " route id comes from the provider plan"))
    return result;
  for (llvm::StringRef header : plan.requiredHeaders)
    if (int result =
            expect(routeHasHeader(route, header),
                   llvm::Twine(context) +
                       " route carries provider-plan required header '" +
                       header + "'"))
      return result;
  if (int result = expectRouteConsumesTypedConfigFacts(
          route, plan.vectorTypeName, plan.vectorCType, plan.vlCType, context))
    return result;
  if (computedMask) {
    if (int result = expect(
            routeHasTypeMapping(route, plan.maskTypeName, plan.maskCType),
            llvm::Twine(context) +
                " route maps computed-mask type from provider-plan facts"))
      return result;
  }
  return expect(routeABIMappingsMatchDescription(route, description),
                llvm::Twine(context) +
                    " route ABI mappings follow provider-plan ABI order");
}

llvm::Expected<tianchenrv::plugin::rvv::
                   RVVSelectedBodyRouteStatementPlanOwnerSelection>
buildSegment2StatementPlanOwnerSelectionForTest(
    tianchenrv::plugin::rvv::RVVSelectedBodyRouteAnalysis &analysis,
    const tianchenrv::plugin::rvv::RVVSelectedBodyRouteMaterializationFacts
        &materializationFacts,
    const tianchenrv::plugin::rvv::
        RVVSelectedBodyMemoryRouteOperandBindingFacts &memoryFacts,
    llvm::StringRef context) {
  auto elementwiseFacts = tianchenrv::plugin::rvv::
      getRVVSelectedBodyElementwiseSelectRouteOperandBindingFacts(analysis,
                                                                  context);
  if (!elementwiseFacts)
    return elementwiseFacts.takeError();
  auto mathFacts =
      tianchenrv::plugin::rvv::getRVVSelectedBodyMathRouteOperandBindingFacts(
          analysis, context);
  if (!mathFacts)
    return mathFacts.takeError();
  auto residualFacts = tianchenrv::plugin::rvv::
      getRVVSelectedBodyResidualRouteOperandBindingFacts(analysis, context);
  if (!residualFacts)
    return residualFacts.takeError();
  return tianchenrv::plugin::rvv::
      getRVVSelectedBodyRouteStatementPlanOwnerSelection(
          analysis, materializationFacts, *elementwiseFacts, memoryFacts,
          *mathFacts, *residualFacts, context);
}

int expectSegment2ProviderBoundaryPreflight(
    tianchenrv::plugin::rvv::RVVSelectedBodyRouteAnalysis &analysis,
    const tianchenrv::plugin::rvv::RVVSelectedBodyRouteMaterializationFacts
        &materializationFacts,
    const tianchenrv::plugin::rvv::
        RVVSelectedBodyMemoryRouteOperandBindingFacts &memoryFacts,
    const tianchenrv::plugin::rvv::
        RVVSelectedBodySegment2RouteFamilyProviderPlan &providerPlan,
    llvm::StringRef context) {
  auto selection = buildSegment2StatementPlanOwnerSelectionForTest(
      analysis, materializationFacts, memoryFacts, context);
  if (!selection)
    return fail(llvm::Twine(context) +
                " statement-plan owner selection: " +
                llvm::toString(selection.takeError()));
  return expectSuccess(
      tianchenrv::plugin::rvv::
          verifyRVVSelectedBodySegment2MemoryRouteProviderFacts(
              analysis, materializationFacts, memoryFacts, providerPlan,
              *selection, context),
      llvm::Twine(context) +
          " accepts segment2 provider-boundary preflight before route "
          "construction");
}

int expectRouteConsumesTypedConfigFacts(
    const tianchenrv::conversion::emitc::TCRVEmitCLowerableRoute &route,
    llvm::StringRef vectorTypeName, llvm::StringRef vectorCType,
    llvm::StringRef vlCType, llvm::StringRef context) {
  if (int result = expect(routeHasTypeMapping(route, "!tcrv_rvv.vl", vlCType),
                          llvm::Twine(context) +
                              " maps VL through typed config facts"))
    return result;
  if (int result =
          expect(routeHasTypeMapping(route, vectorTypeName, vectorCType),
                 llvm::Twine(context) +
                     " maps vector type through typed config facts"))
    return result;
  return 0;
}

mlir::Operation *findFirstNestedOp(VariantOp variant, llvm::StringRef name) {
  mlir::Operation *found = nullptr;
  if (!variant)
    return found;
  variant.getBody().walk([&](mlir::Operation *op) {
    if (found || op == variant.getOperation())
      return;
    if (op->getName().getStringRef() == name)
      found = op;
  });
  return found;
}

unsigned countNestedOps(VariantOp variant, llvm::StringRef name) {
  unsigned count = 0;
  if (!variant)
    return count;
  variant.getBody().walk([&](mlir::Operation *op) {
    if (op != variant.getOperation() && op->getName().getStringRef() == name)
      ++count;
  });
  return count;
}

mlir::func::FuncOp findHighLevelPlaceholder(mlir::ModuleOp module) {
  return module.lookupSymbol<mlir::func::FuncOp>("high_level_placeholder");
}

RVVProbeCapabilityFacts makeSuccessfulProbeFacts() {
  RVVProbeCapabilityFacts facts;
  facts.architecture = "riscv64";
  facts.hartCount = 64;
  facts.vlenbBytes = 16;
  facts.isaVectorHints = "rv64gcv_zvl128b";
  facts.clangAvailable = true;
  facts.clangVersion = "clang version 18.1.3";
  facts.cmakeAvailable = true;
  facts.cmakeVersion = "cmake version 3.28.3";
  facts.minimalRVVCompileRunSucceeded = true;
  facts.selectedMarch = "rv64gcv";
  facts.selectedMABI = "lp64d";
  return facts;
}

int runRegistrationAndCapabilityMetadataTest() {
  ExtensionPluginRegistry registry;
  if (int result = expectSuccess(
          tianchenrv::plugin::registerRVVExtensionPlugin(registry),
          "register RVV plugin"))
    return result;
  if (int result = expect(registry.size() == 1,
                          "RVV plugin registration adds one plugin"))
    return result;
  if (int result = expect(
          registry.lookupPlugin(
              tianchenrv::plugin::rvv::getRVVExtensionPluginName()) != nullptr,
          "registered RVV plugin is lookup-visible"))
    return result;

  llvm::SmallVector<PluginCapability, 16> capabilities;
  registry.collectCapabilities(capabilities);
  if (int result = expect(capabilities.size() == 1,
                          "RVV plugin exposes only the base RVV capability"))
    return result;
  if (int result = expect(registry.lookupCapabilityByID("rvv") != nullptr,
                          "RVV capability id lookup succeeds"))
    return result;

  llvm::SmallVector<SourceFrontDoorPassRegistration, 4> sourceFrontDoorPasses;
  if (int result = expectSuccess(
          registry.collectSourceFrontDoorPasses(sourceFrontDoorPasses),
          "collect RVV source front-door pass registrations"))
    return result;
  if (int result =
          expect(sourceFrontDoorPasses.size() == 4,
                 "RVV plugin exposes legacy, bounded vector-binary, bounded "
                 "vector compare/select, and bounded vector runtime-scalar "
                 "compare/select source front-door pass registrations"))
    return result;
  if (int result =
          expect(sourceFrontDoorPasses[0].getOwnerPlugin() ==
                     tianchenrv::plugin::rvv::getRVVExtensionPluginName(),
                 "RVV legacy source front-door pass is owned by RVV plugin"))
    return result;
  if (int result =
          expect(sourceFrontDoorPasses[0].getArgument() ==
                     "tcrv-rvv-fail-closed-legacy-vector-source-front-door",
                 "RVV source front-door pass exposes the fail-closed legacy argument"))
    return result;
  if (int result = expect(
          !sourceFrontDoorPasses[0].isDefaultArtifactFrontDoorEligible(),
          "RVV legacy source front-door pass is explicit-only and not default "
          "artifact-front-door eligible"))
    return result;
  if (int result =
          expect(sourceFrontDoorPasses[1].getOwnerPlugin() ==
                     tianchenrv::plugin::rvv::getRVVExtensionPluginName(),
                 "RVV bounded vector-binary source front-door pass is owned by "
                 "RVV plugin"))
    return result;
  if (int result = expect(
          sourceFrontDoorPasses[1].getArgument() ==
              "tcrv-rvv-materialize-vector-binary-source-front-door",
          "RVV source front-door pass exposes the bounded vector-binary argument"))
    return result;
  if (int result = expect(
          !sourceFrontDoorPasses[1].isDefaultArtifactFrontDoorEligible(),
          "RVV bounded vector-binary source front-door pass is explicit-only "
          "and not default artifact-front-door eligible"))
    return result;
  if (int result =
          expect(sourceFrontDoorPasses[2].getOwnerPlugin() ==
                     tianchenrv::plugin::rvv::getRVVExtensionPluginName(),
                 "RVV bounded vector compare/select source front-door pass is "
                 "owned by RVV plugin"))
    return result;
  if (int result = expect(
          sourceFrontDoorPasses[2].getArgument() ==
              "tcrv-rvv-materialize-vector-compare-select-source-front-door",
          "RVV source front-door pass exposes the bounded vector compare/select "
          "argument"))
    return result;
  if (int result = expect(
          !sourceFrontDoorPasses[2].isDefaultArtifactFrontDoorEligible(),
          "RVV bounded vector compare/select source front-door pass is "
          "explicit-only and not default artifact-front-door eligible"))
    return result;
  if (int result = expect(
          sourceFrontDoorPasses[3].getOwnerPlugin() ==
              tianchenrv::plugin::rvv::getRVVExtensionPluginName(),
          "RVV bounded vector runtime-scalar compare/select source front-door "
          "pass is owned by RVV plugin"))
    return result;
  if (int result = expect(
          sourceFrontDoorPasses[3].getArgument() ==
              "tcrv-rvv-materialize-vector-runtime-scalar-cmp-select-source-front-door",
          "RVV source front-door pass exposes the bounded vector "
          "runtime-scalar compare/select argument"))
    return result;
  if (int result = expect(
          !sourceFrontDoorPasses[3].isDefaultArtifactFrontDoorEligible(),
          "RVV bounded vector runtime-scalar compare/select source front-door "
          "pass is explicit-only and not default artifact-front-door eligible"))
    return result;
  if (int result =
          expect(static_cast<bool>(sourceFrontDoorPasses[0].getFactory()),
                 "RVV legacy source front-door pass factory is present"))
    return result;
  if (int result =
          expect(static_cast<bool>(sourceFrontDoorPasses[1].getFactory()),
                 "RVV bounded vector-binary source front-door pass factory is "
                 "present"))
    return result;
  if (int result = expect(
          static_cast<bool>(sourceFrontDoorPasses[2].getFactory()),
          "RVV bounded vector compare/select source front-door pass factory is "
          "present"))
    return result;
  if (int result = expect(
          static_cast<bool>(sourceFrontDoorPasses[3].getFactory()),
          "RVV bounded vector runtime-scalar compare/select source front-door "
          "pass factory is present"))
    return result;

  llvm::SmallVector<SourceFrontDoorPassRegistration, 3> familyRegistryPasses;
  if (int result = expectSuccess(
          tianchenrv::plugin::rvv::
              registerRVVVectorSourceFrontDoorFamilyPasses(
                  tianchenrv::plugin::rvv::getRVVExtensionPluginName(),
                  familyRegistryPasses),
          "collect RVV vector source-front-door active family registry"))
    return result;
  if (int result =
          expect(familyRegistryPasses.size() == 3,
                 "RVV vector source-front-door family registry owns exactly "
                 "the bounded binary, compare/select, and runtime-scalar "
                 "compare/select active families"))
    return result;
  for (size_t index = 0; index < familyRegistryPasses.size(); ++index) {
    const SourceFrontDoorPassRegistration &registryPass =
        familyRegistryPasses[index];
    const SourceFrontDoorPassRegistration &pluginPass =
        sourceFrontDoorPasses[index + 1];
    if (int result =
            expect(registryPass.getOwnerPlugin() == pluginPass.getOwnerPlugin(),
                   "RVV active source-front-door family registry preserves "
                   "plugin ownership"))
      return result;
    if (int result =
            expect(registryPass.getArgument() == pluginPass.getArgument(),
                   "RVV plugin consumes active source-front-door pass "
                   "arguments from the family registry"))
      return result;
    if (int result = expect(
            registryPass.isDefaultArtifactFrontDoorEligible() ==
                pluginPass.isDefaultArtifactFrontDoorEligible(),
            "RVV plugin consumes active source-front-door default pipeline "
            "eligibility from the family registry"))
      return result;
    if (int result =
            expect(static_cast<bool>(registryPass.getFactory()),
                   "RVV vector source-front-door family registry exposes "
                   "non-null pass factories"))
      return result;
    std::unique_ptr<mlir::Pass> materializerPass =
        registryPass.getFactory()();
    if (int result =
            expect(static_cast<bool>(materializerPass),
                   "RVV vector source-front-door family registry factory "
                   "creates a materializer pass"))
      return result;
    if (int result = expect(
            materializerPass->getArgument() == registryPass.getArgument(),
            "RVV vector source-front-door family registry factory creates a "
            "family-owned materializer pass argument"))
      return result;
  }
  return 0;
}

int runCapabilityProfileTest() {
  tianchenrv::plugin::rvv::RVVExtensionPlugin plugin;
  llvm::Expected<TargetCapabilitySet> capabilitiesOrError =
      plugin.buildTargetCapabilitiesFromProbeFacts(makeSuccessfulProbeFacts());
  if (!capabilitiesOrError)
    return fail("valid RVV probe facts were rejected: " +
                llvm::toString(capabilitiesOrError.takeError()));

  TargetCapabilitySet capabilities = std::move(*capabilitiesOrError);
  if (int result = expect(capabilities.isCapabilityAvailableByID("rvv"),
                          "RVV profile exposes available rvv capability"))
    return result;
  llvm::SmallVector<const tianchenrv::support::CapabilityDescriptor *, 1>
      configCapabilities;
  capabilities.collectByKind("isa-vector-config", configCapabilities);
  if (int result = expect(configCapabilities.empty(),
                          "RVV probe profile does not manufacture vector "
                          "config capabilities"))
    return result;
  return expect(
      capabilities.isCapabilityAvailableByID(
          tianchenrv::plugin::rvv::getRVVProbeCompileRunCapabilityID()),
      "RVV profile exposes compile/run capability");
}

int runMissingAndDeclineProposalTest(mlir::MLIRContext &context) {
  constexpr llvm::StringLiteral source = R"mlir(
module {
  func.func @high_level_placeholder() {
    return
  }

  tcrv.exec.kernel @missing_rvv {
    tcrv.exec.capability @generic_base {
      id = "generic.base",
      kind = "toolchain"
    }
  }

  tcrv.exec.kernel @missing_hart_count {
    tcrv.exec.capability @rvv {
      id = "rvv",
      kind = "isa-vector",
      architecture = "riscv64",
      isa_vector_hints = "rv64gcv_zvl128b",
      status = "available"
    }
    tcrv.exec.capability @rvv_probe_compile_run {
      id = "rvv.probe.compile_run",
      kind = "toolchain",
      selected_march = "rv64gcv",
      status = "available"
    }
  }
}
)mlir";

  mlir::OwningOpRef<mlir::ModuleOp> module = parseModule(context, source);
  if (!module)
    return fail("failed to parse RVV decline module");
  mlir::func::FuncOp highLevel = findHighLevelPlaceholder(*module);

  ExtensionPluginRegistry registry;
  if (int result = expectSuccess(
          tianchenrv::plugin::registerRVVExtensionPlugin(registry),
          "register RVV plugin for decline test"))
    return result;

  KernelOp missingRVV = findKernel(*module, "missing_rvv");
  TargetCapabilitySet missingCapabilities =
      TargetCapabilitySet::buildFromKernel(missingRVV);
  llvm::SmallVector<VariantProposal, 1> proposals;
  if (int result = expectSuccess(
          registry.collectVariantProposals(
              VariantProposalRequest(highLevel.getOperation(), missingRVV,
                                     missingCapabilities),
              proposals),
          "collect missing RVV proposals"))
    return result;
  if (int result =
          expect(proposals.empty(), "RVV plugin proposes nothing without rvv"))
    return result;

  KernelOp availableRVVNoBody = findKernel(*module, "missing_hart_count");
  TargetCapabilitySet availableRVVCapabilities =
      TargetCapabilitySet::buildFromKernel(availableRVVNoBody);
  llvm::SmallVector<VariantProposalDecline, 1> declines;
  if (int result =
          expectSuccess(registry.collectVariantProposals(
                            VariantProposalRequest(highLevel.getOperation(),
                                                   availableRVVNoBody,
                                                   availableRVVCapabilities),
                            proposals, &declines),
                        "collect RVV no-body proposal decline"))
    return result;
  if (int result = expect(proposals.empty() && !declines.empty(),
                          "available RVV no-body input is a recoverable RVV "
                          "decline"))
    return result;
  return expect(llvm::StringRef(declines.front().getReason())
                    .contains("explicit typed tcrv_rvv extension-family IR"),
                "decline reason explains explicit typed RVV IR requirement");
}

int runCapabilityOnlyProposalAndTypedBodyRequirementTest(
    mlir::MLIRContext &context) {
  constexpr llvm::StringLiteral source = R"mlir(
module {
  func.func @high_level_placeholder() {
    return
  }

  tcrv.exec.kernel @rvv_no_body_capability_only {
    tcrv.exec.capability @rvv {
      id = "rvv",
      kind = "isa-vector",
      architecture = "riscv64",
      isa_vector_hints = "rv64gcv_zvl128b",
      status = "available"
    }
    tcrv.exec.capability @rvv_hart_count {
      id = "rvv.hart_count",
      kind = "uarch",
      count = 64 : i64,
      status = "available"
    }
    tcrv.exec.capability @rvv_vlenb {
      id = "rvv.vlenb_bytes",
      kind = "uarch",
      bytes = 16 : i64,
      status = "available"
    }
    tcrv.exec.capability @rvv_probe_compile_run {
      id = "rvv.probe.compile_run",
      kind = "toolchain",
      selected_march = "rv64gcv",
      status = "available"
    }
    tcrv.exec.capability @rvv_toolchain_march {
      id = "rvv.toolchain.march",
      kind = "toolchain",
      value = "rv64gcv",
      status = "available"
    }
  }

  tcrv.exec.kernel @rvv_missing_typed_body_variant {
    tcrv.exec.capability @rvv {
      id = "rvv",
      kind = "isa-vector",
      status = "available"
    }
    tcrv.exec.variant @rvv_missing_typed_body attributes {
      origin = "rvv-plugin",
      requires = [@rvv]
    } {
    }
  }
}
)mlir";

  mlir::OwningOpRef<mlir::ModuleOp> module = parseModule(context, source);
  if (!module)
    return fail("failed to parse RVV capability-only module");
  KernelOp kernel = findKernel(*module, "rvv_no_body_capability_only");
  mlir::func::FuncOp highLevel = findHighLevelPlaceholder(*module);
  TargetCapabilitySet capabilities =
      TargetCapabilitySet::buildFromKernel(kernel);

  ExtensionPluginRegistry registry;
  if (int result = expectSuccess(
          tianchenrv::plugin::registerRVVExtensionPlugin(registry),
          "register RVV plugin for typed-body requirement test"))
    return result;

  VariantProposalRequest request(highLevel.getOperation(), kernel,
                                 capabilities);
  llvm::SmallVector<VariantProposal, 1> proposals;
  llvm::SmallVector<VariantProposalDecline, 1> declines;
  if (int result = expectSuccess(
          registry.collectVariantProposals(request, proposals, &declines),
          "collect RVV capability-only proposal surface"))
    return result;
  if (int result = expect(proposals.empty(),
                          "RVV no-body capability produces no proposal"))
    return result;
  if (int result = expect(!declines.empty() &&
                              llvm::StringRef(declines.front().getReason())
                                  .contains("explicit typed tcrv_rvv "
                                            "extension-family IR"),
                          "RVV decline explains explicit typed IR requirement"))
    return result;

  mlir::OpBuilder builder(module->getContext());
  llvm::SmallVector<VariantOp, 1> materialized;
  if (int result = expectErrorContains(
          tianchenrv::transforms::collectAndMaterializeVariantProposals(
              builder, registry, request, &materialized),
          {"no viable plugin proposals",
           "explicit typed tcrv_rvv extension-family IR"}))
    return result;

  KernelOp staleKernel = findKernel(*module, "rvv_missing_typed_body_variant");
  TargetCapabilitySet staleCapabilities =
      TargetCapabilitySet::buildFromKernel(staleKernel);
  VariantOp staleVariant = findVariant(staleKernel, "rvv_missing_typed_body");
  if (int result = expectErrorContains(
          registry.verifyVariantLegality(VariantLegalityRequest(
              staleVariant, staleKernel, staleCapabilities)),
          {"explicit typed RVV extension-family body"}))
    return result;
  VariantEmissionPlan stalePlan;
  if (int result = expectErrorContains(
          registry.buildVariantEmissionPlan(
              VariantEmissionRequest(staleVariant, staleKernel,
                                     staleCapabilities,
                                     VariantEmissionRole::DirectVariant),
              stalePlan),
          {"explicit typed RVV extension-family body"}))
    return result;

  return 0;
}

int runMetadataOnlyVariantLegalityRejectionTest(mlir::MLIRContext &context) {
  constexpr llvm::StringLiteral source = R"mlir(
module {
  tcrv.exec.kernel @metadata_without_typed_body_variant {
    tcrv.exec.capability @rvv {
      id = "rvv",
      kind = "isa-vector",
      architecture = "riscv64",
      isa_vector_hints = "rv64gcv_zvl128b",
      status = "available"
    }
    tcrv.exec.variant @rvv_metadata_without_typed_body attributes {
      origin = "rvv-plugin",
      requires = [@rvv],
      tcrv_rvv.policy = "not_a_typed_policy"
    } {
    }
  }
}
)mlir";

  mlir::OwningOpRef<mlir::ModuleOp> module = parseModule(context, source);
  if (!module)
    return fail("failed to parse RVV metadata rejection module");
  KernelOp kernel = findKernel(*module, "metadata_without_typed_body_variant");
  VariantOp variant = findVariant(kernel, "rvv_metadata_without_typed_body");
  TargetCapabilitySet capabilities =
      TargetCapabilitySet::buildFromKernel(kernel);
  tianchenrv::plugin::rvv::RVVExtensionPlugin plugin;
  return expectErrorContains(
      plugin.verifyVariantLegality(
          VariantLegalityRequest(variant, kernel, capabilities)),
      {"explicit typed RVV extension-family body"});
}

